# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import os

def lambda_handler(event, context):
    # Database connection settings
    rds_host = os.environ['RDS_HOST']
    rds_user = os.environ['RDS_USER']
    rds_password = os.environ['RDS_PASSWORD']
    rds_db = os.environ['RDS_DB']

    # Connect to the database
    connection = pymysql.connect(host=rds_host,
                                 user=rds_user,
                                 password=rds_password,
                                 database=rds_db,
                                 cursorclass=pymysql.cursors.DictCursor)

    # Prepare base query
    base_query = "SELECT * FROM products WHERE"
    conditions = []
    parameters = []

    # Get search parameters from the event
    search_params = event.get('queryStringParameters', {})
    
    # Dynamically build conditions based on the parameters
    if 'name' in search_params:
        conditions.append(" name LIKE %s")
        parameters.append("%" + search_params['name'] + "%")
    if 'category' in search_params:
        conditions.append(" category = %s")
        parameters.append(search_params['category'])
    if 'price_min' in search_params:
        conditions.append(" price >= %s")
        parameters.append(float(search_params['price_min']))
    if 'price_max' in search_params:
        conditions.append(" price <= %s")
        parameters.append(float(search_params['price_max']))

    # If there are no conditions, select all
    if not conditions:
        query = "SELECT * FROM products"
    else:
        query = base_query + " AND".join(conditions)
    
    # Execute query
    try:
        with connection.cursor() as cursor:
            cursor.execute(query, parameters)
            result = cursor.fetchall()
            return {
                "statusCode": 200,
                "body": result
            }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": str(e)
        }
    finally:
        connection.close()